// // This module implements a 4-bit DRAM cell with read and write functionalities.
// The cell has a data input (4 bits), a data output (4 bits), a read enable signal,
// and a write enable signal. When the write enable signal is low, the data input
// should be written to the cell. When the read enable signal is low, the data
// stored in the cell should be outputted.
module dram_cell (
    input wire [3:0] data_in,
    output reg [3:0] data_out,
    input wire read_enable,
    input wire write_enable,
    input wire clk
);
    reg [3:0] memory;

    always @(posedge clk) begin
        if (write_enable) begin
            memory <= data_in;
        end
        if (read_enable) begin
            data_out <= memory;
        end
    end
endmodule

